using System.IO;
using OfficeOpenXml;
using OfficeOpenXml.ExcelPackage;
using OfficeOpenXml.ExcelRange;

class ETG_SalesOrderLineQualitySpecUploader
{


}

Method.Source:
/// <summary>
/// Runs the class with the specified arguments.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    System.IO.Stream		    stream;
    ExcelSpreadsheetName	    sheeet;
    FileUploadBuild			    fileUpload;
    DialogGroup				    dlgUploadGroup;
    FileUploadBuild			    fileUploadBuild;
    FormBuildControl		    formBuildControl;

    int                           counter,minrange,maxrange;
    InventTable				      inventTable;       
    SalesTable			          salesTable,salesTableUpd;
    SalesLine		              salesLine;
    ItemId					      itemID;
    SalesId                       salesId;
    InventTransId                 inventTransId;
    ETG_SalesLineQualityGrp       salesLineQualityGrp;
    ETG_PostPackingQualityGrp     postPackingQualityGrp;
    ETGQUALITYSPECIFICATIONGROUP  qualityspecgrp;
    Name                          groupid,maxrangeUpd,minrangeUpd;
    CalculationType               calculationType;
    LineNum                     lineNum;



    Dialog dialog = new Dialog("Import Sales Order Line Quality Specifications");

    dlgUploadGroup		= dialog.addGroup("Select Excel File to Upload.");
    formBuildControl	= dialog.formBuildDesign().control(dlgUploadGroup.name());
    fileUploadBuild		= formBuildControl.addControlEx(classstr(FileUpload), 'Upload');

    fileUploadBuild.style(FileUploadStyle::MinimalWithFilename);
    fileUploadBuild.fileTypesAccepted('.xlsx');


    if (dialog.run() && dialog.closedOk())
    {
        FileUpload fileUploadControl					  = dialog.formRun().control(dialog.formRun().controlId('Upload'));
        FileUploadTemporaryStorageResult fileUploadResult = fileUploadControl.getFileUploadResult();

        if (fileUploadResult != null && fileUploadResult.getUploadStatus())
        {
            stream = fileUploadResult.openResult();
            using (ExcelPackage Package = new ExcelPackage(stream))
            {
                int rowCount, i;

                Package.Load(stream);
                ExcelWorksheet worksheet		= package.get_Workbook().get_Worksheets().get_Item(1);
                OfficeOpenXml.ExcelRange range	= worksheet.Cells;
                rowCount = worksheet.Dimension.End.Row - worksheet.Dimension.Start.Row + 1;

                for (i = 2; i<= rowCount; i++)
                {

                    salesId         = range.get_Item(i, 1).Value;
                    lineNum         = str2Num(range.get_Item(i, 2).Value);
                    groupid         = range.get_Item(i, 3).Value;
                    minrange        = str2Int(range.get_Item(i,7).Value);
                    maxrange        = str2Int(range.get_Item(i,8).Value);

                    qualityspecgrp  = ETGQUALITYSPECIFICATIONGROUP::find(groupid);
                    select firstonly salesLine
                        where salesLine.SalesId ==salesId
                        && salesLine.LineNum == lineNum;

                    salesTable      = SalesTable::find(salesId);
                    select firstonly salesTableUpd
                        where salesTableUpd.SalesId == salesLine.SalesId;

                    if(!salesTable)
                    {
                        error(strFmt('Sales Order %1 does not Exist',salesId));
                    }

                    if(minrange > maxrange)
                    {
                        error(strFmt('Max range should be greater than min range for sales order line %1, %2', salesId, groupid ));
                    }

                    if(maxrange > minrange)
                    {
                        maxrangeUpd = 'Maximum value';
                    }

                    if(minrange > maxrange)
                    {
                        minrangeUpd = 'Minumun value';
                    }

                    if(salesTable && salesLine && qualityspecgrp && maxrangeUpd)
                    {
                        salesLineQualityGrp.clear();
                        postPackingQualityGrp.clear();

                        try
                        { 

                            salesLineQualityGrp.InventTransId            = salesLine.InventTransId;
                            postPackingQualityGrp.InventTransId          = salesLine.InventTransId;
                            salesLineQualityGrp.GroupId                  = range.get_Item(i, 3).Value;
                            postPackingQualityGrp.GroupID                = range.get_Item(i, 3).Value;
                            postPackingQualityGrp.GroupDescription       = qualityspecgrp.GroupDescription;
                            postPackingQualityGrp.SubGroupID             = range.get_Item(i,3).Value;
                            postPackingQualityGrp.SubGroupDescription    = qualityspecgrp.GroupDescription;
                            postPackingQualityGrp.MeasurementType        = str2Enum(calculationType,range.get_Item(i,4).Value);
                            postPackingQualityGrp.Increment              = str2Int(range.get_Item(i,5).Value);
                            postPackingQualityGrp.FixedValue             = str2Int(range.get_Item(i,6).Value);
                            postPackingQualityGrp.MinRange               = str2Int(range.get_Item(i,7).Value);
                            postPackingQualityGrp.MaxRange               = str2Int(range.get_Item(i,8).Value);


                            maxrangeUpd = '';
                            minrangeUpd = '';

                            ttsbegin;
                            if(salesLineQualityGrp.validateWrite()) 
                            {
                                salesLineQualityGrp.insert();
                                postPackingQualityGrp.insert();
                            }

                            ttscommit;
                            counter++;

                        }
                        catch(Exception::Error)
                        {
                            ttsabort;
                        }
                    }

                }
                info(strFmt('Sales Order Lines Quality Specifications Uploaded Sucessfully. Total Lines %1 : ',counter));
            }
        }
        else
        {
            error("Error During Upload. Please Contact System Admin. Item ID %1",itemID);
        }

    }
}
